module alu_32bit(
    input      [31:0] a       ,
    input      [31:0] b       ,
    input      [2:0]  op      ,

    output reg [31:0] output_value
);

always @(*)
begin
    case (op)
        3'b000: output_value = a + b;
        3'b001: output_value = a - b;
        3'b010: output_value = a & b;
        3'b011: output_value = a | b;
        3'b100: output_value = a ^ b;
        default: output_value = 32'b0;
    endcase
end

endmodule
